154	  async doGenerate({
155	    prompt,
156	    files,
157	    mask,
158	    size,
159	    aspectRatio,
160	    seed,
161	    providerOptions,
162	    headers,
163	    abortSignal,
164	  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
165	    Awaited<ReturnType<ImageModelV3['doGenerate']>>
166	  > {
167	    const { body, warnings } = await this.getArgs({
168	      prompt,
169	      files,
170	      mask,
171	      size,
172	      aspectRatio,
173	      seed,
174	      providerOptions,
175	      n: 1,
176	      headers,
177	      abortSignal,
178	    } as Parameters<ImageModelV3['doGenerate']>[0]);
179	
