  'https://api.example.com/v1/images/generate': {
    response: {
      type: 'json-value',
      body: {
        images: [{ b64_json: PLACEHOLDER_B64 }],
        model: 'pixel-art-v1',
        created: 1700000000,
      },
    },
  },
});

describe('PixelArt provider', () => {
  it('creates image models via .image and .imageModel', () => {
    const provider = createPixelArt();

    const imageModel = provider.image('pixel-art-v1');
    const imageModel2 = provider.imageModel('retro-8bit-v1');

    expect(imageModel.provider).toBe('pixelart.image');
    expect(imageModel.modelId).toBe('pixel-art-v1');
    expect(imageModel2.modelId).toBe('retro-8bit-v1');
    expect(imageModel.specificationVersion).toBe('v3');
  });

  it('configures baseURL, Authorization header, and custom headers correctly', async () => {
    const provider = createPixelArt({
      apiKey: 'test-api-key',
      baseURL: 'https://api.example.com/v1',
      headers: {
        'x-custom-header': 'my-value',
      },
    });

    const model = provider.image('pixel-art-v1');

    await model.doGenerate({
      prompt: 'A tiny pixel castle',
      files: undefined,
      mask: undefined,
      n: 1,
      size: '512x512',
      seed: undefined,
      aspectRatio: undefined,
      providerOptions: {},
    });

    expect(server.calls[0].requestUrl).toBe(
      'https://api.example.com/v1/images/generate',
    );
    expect(server.calls[0].requestMethod).toBe('POST');
    expect(server.calls[0].requestHeaders['authorization']).toBe(
      'Bearer test-api-key',
    );
    expect(server.calls[0].requestHeaders['x-custom-header']).toBe('my-value');
    expect(await server.calls[0].requestBodyJson).toMatchObject({
      prompt: 'A tiny pixel castle',
      model: 'pixel-art-v1',
      n: 1,
      size: '512x512',
    });
  });

  it('includes user-agent suffix in requests', async () => {
    const provider = createPixelArt({
      apiKey: 'test-api-key',
      baseURL: 'https://api.example.com/v1',
    });

    const model = provider.image('pixel-art-v1');
    await model.doGenerate({
      prompt: 'Forest scene',
      files: undefined,
      mask: undefined,
      n: 1,
      size: undefined,
      seed: undefined,
      aspectRatio: undefined,
      providerOptions: {},
    });

    expect(server.calls[0].requestUserAgent).toContain('ai-sdk/pixelart/');
  });

  it('throws NoSuchModelError for unsupported model types', () => {
    const provider = createPixelArt();

    expect(() => provider.languageModel('some-id')).toThrowError(
      'No such languageModel',
    );
    expect(() => provider.embeddingModel('some-id')).toThrowError(
      'No such embeddingModel',
    );
    expect(() => provider.textEmbeddingModel('some-id')).toThrowError(
      'No such embeddingModel',
    );
  });
});

