import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const prompt = 'A pixel art dragon breathing fire';

// Minimal base64 payload (single byte) used as a stand-in for real image data
const PLACEHOLDER_B64 = btoa('\xff');

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixel-art-v1', {
    provider: 'pixelart.image',
    baseURL: 'https://api.example.com/v1',
    headers: headers ?? (() => ({ Authorization: 'Bearer test-key' })),
    fetch,
    _internal: { currentDate },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/v1/images/generate': {
      response: {
        type: 'json-value',
        body: {
          images: [{ b64_json: PLACEHOLDER_B64 }],
          model: 'pixel-art-v1',
          created: 1700000000,
        },
      },
    },
  });

  describe('doGenerate', () => {
    it('sends the correct request body for a basic generation', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '512x512',
        seed: 42,
        aspectRatio: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixel-art-v1',
        prompt,
        n: 1,
        size: '512x512',
        seed: 42,
      });
    });

    it('forwards style and pixelDensity provider options', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 2,
        size: '256x256',
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {
          pixelart: {
            style: 'retro',
            pixelDensity: 8,
          },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixel-art-v1',
        prompt,
        n: 2,
        size: '256x256',
        style: 'retro',
        pixel_density: 8,
      });
    });

    it('omits size, seed, style, and pixelDensity when not provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).not.toHaveProperty('size');
      expect(body).not.toHaveProperty('seed');
      expect(body).not.toHaveProperty('style');
      expect(body).not.toHaveProperty('pixel_density');
    });

    it('returns decoded Uint8Array images', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBeInstanceOf(Uint8Array);
    });

    it('returns providerMetadata with created timestamp', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
      });

      expect(result.providerMetadata?.pixelart).toStrictEqual({
        created: 1700000000,
      });
    });

    it('returns correct response metadata', async () => {
      const testDate = new Date('2025-06-01T00:00:00Z');
      const model = createBasicModel({ currentDate: () => testDate });

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
      });

      expect(result.response).toStrictEqual({
        timestamp: testDate,
        modelId: 'pixel-art-v1',
        headers: expect.any(Object),
      });
    });

    it('emits an unsupported warning when aspectRatio is supplied', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        seed: undefined,
        aspectRatio: '16:9',
        providerOptions: {},
      });

      expect(result.warnings).toMatchInlineSnapshot(`
        [
          {
            "details": "PixelArt does not support aspectRatio. Use the size parameter (e.g. "512x512") to control image dimensions.",
            "feature": "aspectRatio",
            "type": "unsupported",
          },
        ]
      `);
    });

    it('produces no warnings when no unsupported options are used', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '512x512',
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: { pixelart: { style: '8bit', pixelDensity: 16 } },
      });

      expect(result.warnings).toHaveLength(0);
    });

    it('merges provider and per-request headers', async () => {
      const modelWithHeaders = createBasicModel({
        headers: () => ({
          Authorization: 'Bearer test-key',
          'X-Provider-Header': 'provider-value',
        }),
      });

      await modelWithHeaders.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
        headers: { 'X-Request-Header': 'request-value' },
      });

      expect(server.calls[0].requestHeaders).toMatchObject({
        authorization: 'Bearer test-key',
        'x-provider-header': 'provider-value',
        'x-request-header': 'request-value',
      });
    });

    it('handles API errors', async () => {
      server.urls['https://api.example.com/v1/images/generate'].response = {
        type: 'error',
        status: 400,
        body: JSON.stringify({
          error: { message: 'Invalid style value', type: 'invalid_request' },
        }),
      };

      const model = createBasicModel();

      await expect(
        model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          seed: undefined,
          aspectRatio: undefined,
          providerOptions: {},
        }),
      ).rejects.toMatchObject({
        message: 'Invalid style value',
        statusCode: 400,
      });
    });

    it('supports multiple images in a single call', async () => {
      server.urls['https://api.example.com/v1/images/generate'].response = {
        type: 'json-value',
        body: {
          images: [
            { b64_json: PLACEHOLDER_B64 },
            { b64_json: PLACEHOLDER_B64 },
            { b64_json: PLACEHOLDER_B64 },
          ],
          model: 'pixel-art-v1',
          created: 1700000001,
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 3,
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(3);
      result.images.forEach(img => expect(img).toBeInstanceOf(Uint8Array));
    });
  });

  describe('constructor', () => {
    it('exposes correct provider and model information', () => {
      const model = createBasicModel();

      expect(model.provider).toBe('pixelart.image');
      expect(model.modelId).toBe('pixel-art-v1');
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(4);
    });
  });
});
